import{_ as a,o as t,c as b,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"逆转系列外挂","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/逆转系列外挂.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/逆转系列外挂.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/逆转系列外挂.md"};function o(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"逆转系列外挂",tabindex:"-1"},[n("逆转系列外挂 "),r("a",{class:"header-anchor",href:"#逆转系列外挂","aria-label":'Permalink to "逆转系列外挂"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001E")])])],-1),p('<h1 id="逆转系列外挂-1" tabindex="-1">逆转系列外挂 <a class="header-anchor" href="#逆转系列外挂-1" aria-label="Permalink to &quot;逆转系列外挂&quot;">​</a></h1><p>逆转系列外挂<br> 众所周知，学习教育方法的是教师，所以学习法律的自然是法师（？），法律学多了会不会丧失人性这倒是不清楚，但身为一位优秀的法师，在法庭上用用各种奇怪的魔法超能力什么的，这再合理不过了（？）。至少可以确定的是，在逆转裁判的世界，你就可以见识到各位主角们的外挂。</p><p>注入灵力的勾玉<br> D+500<br> 魔幻本质<br> 逆转裁判世界观中的克莱因王国的一些居民以及绫里家族都会佩戴勾玉，大概像道士的拂尘一样是灵媒师的法器，但没有注入灵力的勾玉是没有作用的，在逆转裁判2中春美为勾玉注入灵力后激活了力量。<br> 拥有勾玉后当面前的目标对你有所隐瞒时你的眼中将显现交错的锁链，其中有着1~5道锁，这就是精神枷锁。精神枷锁代表了面前的人对你隐瞒的意愿，精神枷锁越多，则隐瞒的意愿越强烈，当你通过各种方法，譬如举证逼问、用某种东西利诱等，成功提升了对方将秘密说出的意愿，你的眼中会出现锁破碎的场景，因为精神枷锁的数量代表了隐瞒的意愿，所以如果对方是一个极为感性的人，也可能出现上一秒还是5把精神枷锁，给予她心心念念的大明星的签名后一瞬间所有精神枷锁全部解开的情况。精神枷锁一般为红色，但是某些罕见的情况下也会出现黑色的精神枷锁。红色的枷锁是主动隐瞒的秘密，黑色的枷锁是本人也不知道的，因为某种原因被潜意识隐瞒的秘密。譬如心灵承受过极其严重的创伤导致失去了那部分记忆，或者极端偏执的性格让自己下意识的忘记了什么事，如果想要强行解开这种锁，说不定会让对方的精神崩溃。通过这份能力，通过观察心锁是否松动，在与浮现心锁的目标进行交流时能更容易地找出应当交谈的方向与方法，这令你的社交检定获得等同于智力上附加成功的增强加值。</p><p>ST选开：勾玉的灵力会逐渐消耗殆尽，大约10年就会变回普通的勾玉，这时就需要支付500分请主神重新赋予灵力了。</p><p>手镯<br> D+500<br> 科技本质（这玩意真的可以科学解释吗？）<br> 原本属于或真敷优海的手镯，后来其中之一传给了王泥喜法介。原本是魔术师的道具，但对于法师也是有用的道具。根据或真敷扎克的说法，这个手镯是用特殊金属制作，佩戴后能根据佩戴者的手臂发生变化，严丝合缝地贴合皮肤，人在紧张时肌肉会发生抽搐，这种紧张感被无意识地感知到后，感知者在无意识间肌肉也会发生同样轻微的抽搐，但因为手镯是完全贴合的，这种的细微抽搐也会产生不适感，通过这样的原理手镯的佩戴者便能感知到对方的紧张。因为察觉到对方的紧张，佩戴者能专注地观察对方的小动作微表情等，以此来判断是否说谎。以被察觉到紧张感的角色为目标进行侦查检定时获得等同于专注技能/2的增强加值。</p><p>模拟太<br> D+500<br> 科技本质<br> 希月心音脖子上的人工智能伴侣和便携式电脑，表面上是一个挂着有科技感的可爱公仔的项链。作为电脑时将投影出屏幕，配合配套的三指手套进行触屏操作，能起到普通的电脑一样的作用。<br> 情绪矩阵：模拟太中的一个程序。需要时，使用者可以使用一个标准动作在当前场景中启动情绪矩阵。若佩戴者具有心理学专业，且具有高度敏感的听力（一般为感知6及以上），则可以用模拟太捕捉声音中隐藏的微妙的情绪变化，通过模拟太检测对方高兴/愤怒/悲伤/惊讶这四种情绪存在与否，及情绪的程度，并显示在屏幕的四角。以此为线索进行下一步的询问，这是一个C级读心效果。但当对方情绪极为强烈时，便会进入情绪过载状态，对应一角的情绪剧烈波动，其他三角的情绪暂时不可见。此外，模拟太还有基本的感知杂音的能力，若杂音存在，就意味着对方说出了虚假的事实，这可能是对方故意说出的谎言，也可能是对方由于极端情绪导致的错误发言。<br> 此外，模拟太有时会说出佩戴者的心声，虽然这对使用者是个困扰，但如果是不能说话的时候或许有点用吧，这视为C级沉默免疫。</p><p>盗乐宝<br> D+500<br> 科技本质<br> 盗取真相的义贼，八咫乌。偷取获得非法证据以执行正义的组织，作为成员之一，身为偷盗者的一条九郎，拥有一台用于预演盗窃的装置，这就是盗乐宝，外表类似一台黑色的小灵通。一条九郎死后，一条美云继承了这台装置，与御剑怜侍相遇后多次使用盗乐宝还原现场，以帮助御剑进行推理。<br> 现场模拟：只需要用自由动作输入相应的数据，就能用全息投影的方式复现想要复现的场景，没有相关信息的部分无法复现，或者只能复现出模糊的影子，使用错误信息复现的部分则自然是错误的。自然，除了复现，你自然也可以输入数据来模拟未发生的景象。这视为一个D级幻象效果。但这个幻象半透明，且色调比较单一，甚至不会进行运动，所以无法起到欺骗的作用。<br> 此外盗乐宝还具有3D扫描的功能，通过盗乐宝扫描场景即可记录当前场景中的一切。这视为一次预设的搜索，搜索掷骰为19+2。特殊的，这个搜索检定不会直接得出信息，只能在之后将场景投影后对投影进行搜索来获取信息。对记录的场景投影进行搜索，其成功值不会超过记录时掷骰的成功值。盗乐宝的半透明投影及其优秀的扫描能力对于探查很有帮助，对场景进行扫描及对复现的投影进行搜索，这两种搜索检定均获得1附加成功。（所以预设搜索的实际搜索掷骰为19+3）</p><p>ST选开：<br> 福尔摩斯兔玩偶<br> D+500<br> 科技本质<br> 成步堂事务所的律师们都有特别的力量呢，身为成步堂龙一的先祖，身处明治时代的成步堂龙之介就没有那么花里胡哨的科技，更没有什么魔法，只不过有个福尔摩斯朋友而已。<br> 福尔摩斯兔玩偶看似是一个福尔摩斯打扮的小小兔子玩偶，实际上是爱丽丝·华生制作的超越时代的通讯设备。通讯的另一端正是那位居住在贝克街221b的大侦探，夏洛克·福尔摩斯。出于无聊，福尔摩斯与主神进行了一个打发无聊的交易。每天一次，轮回者可以拉动玩偶的耳朵与这位侦探进行对话，将自己的发现告诉对方，让这位大侦探提供一些建议。但需要注意的是，大侦探也有自己的秉性，帮忙制定犯罪计划什么的，他大概率是不会同意的，如果想要对他说谎，也要考虑一下这位大侦探识破谎言的能力，此外，《大逆转裁判》的福尔摩斯和原著的福尔摩斯有所区别，虽然同样能轻易看穿真相，但他是一个更滑稽的家伙，这不仅体现在语言上，在推理时他也更喜欢装傻，很多时候会故意进行一番关注点正确，但过程与结论大错特错的推理来引导你自己找出真相。<br> 当然，大侦探只有一个，所以同队中只能有一个兔玩偶。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
